parameters.jsCode:
const raw = $input.first().json.message.content;

const cleaned = raw
  .replace(/^\uFEFF/, '')
  .replace(/```json\s*/gi, '')
  .replace(/```\s*/g, '')
  .trim();

// Fix unescaped control characters inside JSON string values
const sanitized = cleaned.replace(
  /"caption"\s*:\s*"([\s\S]*?)(?<!\\)"/,
  (_, captionValue) => {
    const fixed = captionValue
      .replace(/\r\n/g, '\\n')   // Windows line breaks
      .replace(/\r/g, '\\n')     // old Mac line breaks
      .replace(/\n/g, '\\n')     // Unix line breaks
      .replace(/\t/g, '\\t');    // tabs
    return `"caption":"${fixed}"`;
  }
);

let data;
try {
  data = JSON.parse(sanitized);
} catch (e) {
  const match = sanitized.match(/\{[\s\S]*\}/);
  if (match) {
    data = JSON.parse(match[0].replace(/[\n\r\t]/g, ' '));
  } else {
    throw new Error(`Failed to parse JSON: ${e.message} | Raw: ${cleaned}`);
  }
}

return [{ json: data }];

const data = $input.first().json;
const canvasWidth = 1024;
const margin = 20;

// Max area resize guarantees logo fits within 170x130
// Use 170 as safe max width for position calculation
const logoWidth = 170;
const yPos = margin;

let xPos;
const position = data.logo_position?.trim() ?? "Top Left";

if (position === "Top Left") {
  xPos = margin;
} else if (position === "Top Right") {
  xPos = canvasWidth - logoWidth - margin;
} else {
  xPos = Math.round((canvasWidth - logoWidth) / 2);
}

return { json: {
  x_position: xPos,
  y_position: yPos
}};

